using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Data;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

internal static class TestHelper
{
    public static SchoolContext CreateInMemoryContext([System.Runtime.CompilerServices.CallerMemberName] string dbName = null)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName + "_" + Guid.NewGuid().ToString("N"))
            .Options;
        var context = new SchoolContext(options);
        context.Database.EnsureCreated();
        return context;
    }

    public static void SeedStudents(SchoolContext context)
    {
        context.Students.AddRange(
            new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = new DateTime(2021, 9, 1) },
            new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = new DateTime(2020, 9, 1) }
        );
        context.SaveChanges();
    }

    public static void SeedInstructors(SchoolContext context)
    {
        context.Instructors.AddRange(
            new Instructor { FirstMidName = "Kim", LastName = "Abercrombie", HireDate = new DateTime(1995, 3, 11) },
            new Instructor { FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = new DateTime(2002, 7, 6) },
            new Instructor { FirstMidName = "Roger", LastName = "Harui", HireDate = new DateTime(1998, 7, 1) }
        );
        context.SaveChanges();
    }

    public static void SeedDepartments(SchoolContext context)
    {
        // Seed instructors first if none exist
        if (!context.Instructors.Any())
        {
            SeedInstructors(context);
        }

        var instructor = context.Instructors.First();
        context.Departments.AddRange(
            new Department { Name = "English", Budget = 350000, StartDate = new DateTime(2007, 9, 1), InstructorID = instructor.ID },
            new Department { Name = "Mathematics", Budget = 100000, StartDate = new DateTime(2007, 9, 1) },
            new Department { Name = "Engineering", Budget = 350000, StartDate = new DateTime(2007, 9, 1) }
        );
        context.SaveChanges();
    }

    public static void SeedCourses(SchoolContext context)
    {
        // Seed departments first if none exist
        if (!context.Departments.Any())
        {
            SeedDepartments(context);
        }

        var dept = context.Departments.First();
        context.Courses.AddRange(
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID },
            new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = dept.DepartmentID },
            new Course { CourseID = 1045, Title = "Calculus", Credits = 4, DepartmentID = dept.DepartmentID }
        );
        context.SaveChanges();
    }

    public static void SeedAll(SchoolContext context)
    {
        SeedStudents(context);
        SeedInstructors(context);
        SeedDepartments(context);
        SeedCourses(context);
    }
}

