using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _service;

    [TestInitialize]
    public void TestInitialize()
    {
        _service = new NotificationService();
        // Drain the static queue to ensure test isolation
        while (_service.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _service?.Dispose();
    }

    [TestMethod]
    public void SendNotification_EnqueuesNotification()
    {
        // Act
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Act
        var result = _service.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void SendNotification_Create_GeneratesCorrectMessage()
    {
        // Act
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_Update_GeneratesCorrectMessage()
    {
        // Act
        _service.SendNotification("Course", "1050", "Chemistry", EntityOperation.UPDATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_Delete_GeneratesCorrectMessage()
    {
        // Act
        _service.SendNotification("Department", "3", "Engineering", EntityOperation.DELETE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdFormat()
    {
        // Act
        _service.SendNotification("Student", "42", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithUserName_SetsCreatedBy()
    {
        // Act
        _service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "AdminUser");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("AdminUser", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        // Act
        _service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_SetsIsReadToFalse()
    {
        // Act
        _service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_SetsOperationString()
    {
        // Act
        _service.SendNotification("Student", "1", EntityOperation.UPDATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("UPDATE", notification.Operation);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAt()
    {
        // Arrange
        var before = DateTime.Now;

        // Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var after = DateTime.Now;
        var notification = _service.ReceiveNotification();
        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
    }

    [TestMethod]
    public void SendNotification_MultipleNotifications_ReceiveInOrder()
    {
        // Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        _service.SendNotification("Course", "2", EntityOperation.UPDATE);
        _service.SendNotification("Department", "3", EntityOperation.DELETE);

        // Assert — FIFO order
        var first = _service.ReceiveNotification();
        Assert.AreEqual("Student", first.EntityType);
        Assert.AreEqual("CREATE", first.Operation);

        var second = _service.ReceiveNotification();
        Assert.AreEqual("Course", second.EntityType);
        Assert.AreEqual("UPDATE", second.Operation);

        var third = _service.ReceiveNotification();
        Assert.AreEqual("Department", third.EntityType);
        Assert.AreEqual("DELETE", third.Operation);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        // Act & Assert — no exception
        _service.Dispose();
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert — no exception (no-op for in-memory implementation)
        _service.MarkAsRead(999);
    }

    [TestMethod]
    public void SendNotification_WithEmptyDisplayName_UsesIdFormat()
    {
        // Act
        _service.SendNotification("Student", "42", "   ", EntityOperation.CREATE);

        // Assert — whitespace display name should fall back to ID format
        var notification = _service.ReceiveNotification();
        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
    }
}

