    private static void SeedInstructorsWithCourses(SchoolContext context)
    {
        var instructor1 = new Instructor
        {
            FirstMidName = "Kim",
            LastName = "Abercrombie",
            HireDate = new DateTime(1995, 3, 11),
            CourseAssignments = new List<CourseAssignment>(),
            OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
        };
        var instructor2 = new Instructor
        {
            FirstMidName = "Fadi",
            LastName = "Fakhouri",
            HireDate = new DateTime(2002, 7, 6),
            CourseAssignments = new List<CourseAssignment>()
        };
        context.Instructors.AddRange(instructor1, instructor2);
        context.SaveChanges();

        var dept = new Department
        {
            Name = "English",
            Budget = 350000,
            StartDate = new DateTime(2007, 9, 1),
            InstructorID = instructor1.ID
        };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course1 = new Course { CourseID = 2021, Title = "Composition", Credits = 3, DepartmentID = dept.DepartmentID };
        var course2 = new Course { CourseID = 2042, Title = "Literature", Credits = 4, DepartmentID = dept.DepartmentID };
        context.Courses.AddRange(course1, course2);
        context.SaveChanges();

        context.CourseAssignments.Add(new CourseAssignment
        {
            InstructorID = instructor1.ID,
            CourseID = course1.CourseID
        });
        context.SaveChanges();
    }

